<template>
  <view class="container">
    <view class="header">
      <text class="title">积极分子申请</text>
    </view>

    <view class="form">
      <view class="form-item">
        <text class="label">申请说明</text>
        <textarea v-model="details" placeholder="请输入申请说明"></textarea>
      </view>
      <view class="form-item">
        <text class="label">附件（图片）</text>
        <view class="upload-list">
          <view class="upload-item" v-for="(u,i) in attachments" :key="i">
            <image :src="u" mode="aspectFill" class="thumb" />
            <text class="remove" @click="removeAttachment(i)">删除</text>
          </view>
          <button type="button" class="btn" @click="chooseImage">选择图片</button>
        </view>
      </view>
      <button type="button" class="submit" @click="onSubmit">提交申请</button>
    </view>
  </view>
</template>

<script setup>
  import { ref } from 'vue'
  import { uploadAPI, applicationAPI } from '@/utils/api.js'

  const details = ref('')
  const attachments = ref([])

  const chooseImage = () => {
    uni.chooseImage({
      count: 6,
      success: async (res) => {
        for (const fp of res.tempFilePaths) {
          try {
            const { url } = await uploadAPI.uploadFile(fp)
            attachments.value.push(url)
          } catch (e) {
            uni.showToast({ title: '上传失败', icon: 'none' })
          }
        }
      }
    })
  }

  const removeAttachment = (i) => {
    attachments.value.splice(i, 1)
  }

  const onSubmit = async () => {
    if (!details.value) {
      uni.showToast({ title: '请填写申请说明', icon: 'none' })
      return
    }
    try {
      const [resp] = await applicationAPI.applyPositive(details.value, attachments.value)
      if (resp.statusCode === 200 && resp.data?.code === 200) {
        uni.showToast({ title: '已提交', icon: 'success' })
        setTimeout(() => uni.navigateBack(), 800)
      } else {
        uni.showToast({ title: resp.data?.message || '提交失败', icon: 'none' })
      }
    } catch (e) {
      uni.showToast({ title: '提交失败', icon: 'none' })
    }
  }
	
</script>

<style lang="scss" scoped>
	// 颜色变量
	$primary-color: #1677ff;
	$secondary-color: #6b7280;
	$text-color: #333;
	$light-bg: #f5f7fa;
	$border-color: #e5e7eb;
	$card-bg: #fff;
	$status-color: #4ade80;
	
	.container {
	  background-color: $light-bg;
	  min-height: 100vh;
	  padding: 20px 15px;
	}
	
	.header {
	  margin-bottom: 20px;
	  
	  .title {
	    font-size: 20px;
	    font-weight: bold;
	    color: $text-color;
	    display: block;
	    text-align: center;
	  }
	}
	
  .form { background:#fff; border-radius:12px; padding:15px; box-shadow: 0 2px 5px rgba(0,0,0,0.05); }
  .form-item { margin-bottom: 15px; }
  .label { display:block; margin-bottom:8px; color:$text-color; }
  textarea { width:100%; border:1px solid $border-color; border-radius:8px; min-height: 160rpx; }
  .submit { width:100%; height:44px; background:$primary-color; color:#fff; border-radius:22px; }
  .upload-list { display:flex; gap:12rpx; flex-wrap:wrap; }
  .upload-item { position:relative; }
  .thumb { width:160rpx; height:160rpx; border-radius:8rpx; background:#f2f3f5; }
  .remove { position:absolute; right:4rpx; top:4rpx; background:rgba(0,0,0,.6); color:#fff; font-size:20rpx; padding:2rpx 6rpx; border-radius:4rpx; }
</style>
    
